// Test stackalloc with native-sized integers (nint / nuint)

Console.WriteLine($"nint size: {sizeof(nint)} bytes");
Console.WriteLine($"nuint size: {sizeof(nuint)} bytes");

// stackalloc Span<nint>
Span<nint> signed = stackalloc nint[4];
signed[0] = 10;
signed[1] = 20;
signed[2] = 30;
signed[3] = nint.MaxValue;

Console.WriteLine("\nSpan<nint> via stackalloc:");
for (int i = 0; i < signed.Length; i++)
    Console.WriteLine($"  [{i}] = {signed[i]}");

// stackalloc Span<nuint>
Span<nuint> unsigned = stackalloc nuint[3];
unsigned[0] = 100;
unsigned[1] = 200;
unsigned[2] = nuint.MaxValue;

Console.WriteLine("\nSpan<nuint> via stackalloc:");
for (int i = 0; i < unsigned.Length; i++)
    Console.WriteLine($"  [{i}] = {unsigned[i]}");

Console.WriteLine("\n✓ stackalloc with nint/nuint works!");

